/**
 * @param {number[][]} points
 * @param {number[]} target
 * @return {number}
 */
function solve(points, target) {
    // Helper to convert point array to a string key for Set storage
    const pointToKey = (point) => point.join(',');

    // Set to store all unique points generated so far
    let currentPoints = new Set();
    for (const p of points) {
        currentPoints.add(pointToKey(p));
    }

    // Check for target in the initial set (k=0)
    const targetKey = target.join(',');
    if (currentPoints.has(targetKey)) {
        return 0;
    }

    // The maximum number of unique points is constrained by the initial size (<= 20) and the reachable space (0-6).
    // Since the coordinates are small (0-6), the search space is finite.
    // If we reach a point where no new points can be generated, and the target hasn't been found, it's unreachable.

    let k = 0;
    // We use a loop that simulates generations until the target is found or no new points are generated.
    while (true) {
        k++;

        // Get the current set of points (as arrays)
        const pointList = Array.from(currentPoints).map(key => key.split(',').map(Number));

        const newPointsKeys = new Set();
        const generatedPoints = [];

        // Generate next generation points
        // We must consider all pairs from *all* previous generations, which are stored in currentPoints.
        // Since we only add points to currentPoints, iterating over pointList is sufficient.

        const N = pointList.length;

        // Iterate over all unique pairs (a, b) from the current set of known points
        for (let i = 0; i < N; i++) {
            for (let j = i + 1; j < N; j++) {
                const p1 = pointList[i];
                const p2 = pointList[j];

                // The problem states: "two *different* points".
                // Since we are iterating over unique indices i != j from a list of unique points (represented by keys),
                // the points themselves are guaranteed to be distinct coordinates.
                // (If the initial points had duplicates, the problem says they don't).

                const nextPoint = [
                    Math.floor((p1[0] + p2[0]) / 2),
                    Math.floor((p1[1] + p2[1]) / 2),
                    Math.floor((p1[2] + p2[2]) / 2)
                ];

                const nextPointKey = nextPoint.join(',');

                if (!currentPoints.has(nextPointKey)) {
                    newPointsKeys.add(nextPointKey);
                    generatedPoints.push(nextPoint);
                }
            }
        }

        if (generatedPoints.length === 0) {
            // No new points were generated in this generation. If the target wasn't found, it won't be.
            return -1;
        }

        // Add all newly generated points to the set of known points
        for (const newPoint of generatedPoints) {
            currentPoints.add(newPoint.join(','));

            // Check if the target is newly generated
            if (newPoint[0] === target[0] && newPoint[1] === target[1] && newPoint[2] === target[2]) {
                return k;
            }
        }

        // Safety break: Although the problem space is small (0-6), if we run for too long, something might be wrong, 
        // but given the constraints, the check for generatedPoints.length === 0 should handle termination.
    }
