use std::collections::HashSet;

fn solve(points: Vec<Vec<i64>>, target: Vec<i64>) -> i64 {
    // Helper function to convert a point (Vec<i64>) to a string key for HashSet storage
    let point_to_key = |p: &Vec<i64>| -> String {
        format!("{},{},{}", p[0], p[1], p[2])
    };

    // Set to store all unique points generated so far
    let mut current_points_keys: HashSet<String> = HashSet::new();
    for p in points.iter() {
        current_points_keys.insert(point_to_key(p));
    }

    // Check for target in the initial set (k=0)
    let target_key = point_to_key(&target);
    if current_points_keys.contains(&target_key) {
        return 0;
    }

    let mut k: i64 = 0;

    // Loop simulating generations
    loop {
        k += 1;

        // Get the current set of points as Vec<Vec<i64>>
        let mut point_list: Vec<Vec<i64>> = Vec::new();
        for key in current_points_keys.iter() {
            let parts: Vec<i64> = key.split(',').map(|s| s.parse().unwrap()).collect();
            point_list.push(parts);
        }

        let mut new_points_keys: HashSet<String> = HashSet::new();
        let mut newly_generated_points: Vec<Vec<i64>> = Vec::new();

        // Generate next generation points by pairing all *distinct* points currently known.
        let n = point_list.len();

        // Iterate over all unique pairs (a, b) where a and b are distinct points from the set.
        for i in 0..n {
            for j in (i + 1)..n {
                let p1 = &point_list[i];
                let p2 = &point_list[j];

                // Calculate the next point c = floor((a+b)/2)
                let next_point = vec![
                    (p1[0] + p2[0]) / 2,
                    (p1[1] + p2[1]) / 2,
                    (p1[2] + p2[2]) / 2,
                ];

                let next_point_key = point_to_key(&next_point);

                // Only consider points that are truly new to the entire set so far
                if !current_points_keys.contains(&next_point_key) {
                    if !new_points_keys.contains(&next_point_key) {
                        new_points_keys.insert(next_point_key.clone());
                        newly_generated_points.push(next_point.clone());
                    }
                }
            }
        }

        if newly_generated_points.is_empty() {
            // No new points were generated in this generation. Target is unreachable.
            return -1;
        }

        // Add all newly generated points to the set of known points
        for new_point in newly_generated_points.iter() {
            let new_key = point_to_key(new_point);
            current_points_keys.insert(new_key.clone());

            // Check if the target is newly generated
            if new_point[0] == target[0] && new_point[1] == target[1] && new_point[2] == target[2] {
                return k;
            }
        }

        // Continue to the next generation
    }
}
